mapper.sql:
WHERE 1 = 1
AND type = #{type}
AND dataOrigin = #{dataOrigin}
AND dminsttNm LIKE CONCAT('%', #{dminsttNm}, '%')
AND dminsttNmDetail LIKE CONCAT('%', #{dminsttNmDetail}, '%')
AND cntrctNm LIKE CONCAT('%', #{contractName}, '%')
AND FIND_IN_SET(prdctClsfcNo, #{categoryNames}) > 0
AND cntctCnclsMthdNm = #{cntctCnclsMthdNm}
AND firstCntrctDate = #{firstCntrctDate}
AND cntrctDate >= CONCAT(#{year}, '-01-01') AND cntrctDate < CONCAT(#{year} + 1, '-01-01')
AND cntrctDate LIKE CONCAT(#{month}, '%')
AND cntrctDate >= CONCAT(#{rangeStart}, '-01') AND cntrctDate < DATE_FORMAT(DATE_ADD(CONCAT(#{rangeEnd}, '-01'), INTERVAL 1 MONTH), '%Y-%m-%d')
AND saved = 'Y'

